request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?msgName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1cd93309017949fdbebf0f7d7ea50b4a" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .
  ?task bboExt:initiatingParticipantRef ?initPartRef .

  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .
  {
    ?mf bboExt:sourceRef ?initPartRef .
  } UNION {
    ?mf bboExt:targetRef ?initPartRef .
  }

  OPTIONAL {
    ?mf bboExt:messageRef ?msgRef .
    ?msg a bboExt:Message .
    ?msg tai:belongsTo ?def .
    FILTER(STRENDS(STR(?msg), ?msgRef))
    ?msg bbo:name ?msgName .
  }

  # Only tasks with exactly 2 message flows
  FILTER EXISTS {
    SELECT ?task2 (COUNT(DISTINCT ?mf2) AS ?cnt) WHERE {
      ?task2 a bboExt:ChoreographyTask .
      ?task2 bboExt:initiatingParticipantRef ?ip2 .
      ?mf2 a bboExt:MessageFlow .
      ?mf2 tai:belongsTo ?choreo .
      {
        ?mf2 bboExt:sourceRef ?ip2 .
      } UNION {
        ?mf2 bboExt:targetRef ?ip2 .
      }
    }
    GROUP BY ?task2
    HAVING (COUNT(DISTINCT ?mf2) = 2)
  }
}
ORDER BY ?taskName
